package com.example.bankingapp;

import android.os.Bundle;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {

    private double accountBalance = 1000.00; // Example initial balance

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        TextView balanceTextView = findViewById(R.id.balanceTextView);
        balanceTextView.setText("Balance: $" + accountBalance);
    }

    public boolean processTransaction(double amount, boolean isDeposit) {
        if (isDeposit) {
            accountBalance += amount;
            return true;
        } else {
            if (accountBalance >= amount) {
                accountBalance -= amount;
                return true;
            } else {
                return false; // Insufficient funds
            }
        }
    }

    public double getAccountBalance() {
        return accountBalance;
    }
}

